INSERT INTO `contact_messages` (`id`, `full_name`, `email`, `message`, `submitted_at`) VALUES
(4, 'Dimitriοs Kandylis', 'dmts@gmail.com', 'ΟΛΑ ΤΕΛΕΙΑ!', '2026-05-30 10:48:43');
INSERT INTO `destinations` (`id`, `name_gr`, `name_en`, `vacation_type`, `landscape`, `best_season_gr`, `best_season_en`, `cost_per_day`, `description_gr`, `description_en`, `guide_gr`, `guide_en`, `image_url`) VALUES
(1, 'Αθήνα', 'Athens', 'Ιστορικός', 'Πόλη', 'Παντός Καιρού', 'All Year', 60, 'Η ιστορική πρωτεύουσα με αμέτρητα μνημεία, την Ακρόπολη και γραφικές γειτονιές.', 'The historic capital with countless monuments, the Acropolis, and picturesque neighborhoods.', '📍 <b>Αξιοθέατα:</b> Ακρόπολη, Μουσείο Ακρόπολης, Πλάκα.<br>🍽️ <b>Γεύσεις:</b> Σουβλάκι στο Μοναστηράκι.<br>💡 <b>Tip:</b> Χρησιμοποιήστε το Μετρό για τις μετακινήσεις σας.', '📍 <b>Sights:</b> Acropolis, Acropolis Museum, Plaka.<br>🍽️ <b>Food:</b> Souvlaki in Monastiraki.<br>💡 <b>Tip:</b> Use the Metro for easy transportation.', 'https://images.unsplash.com/photo-1603565816030-6b389eeb23cb?q=80&w=1170&auto=format&fit=crop&ixlib=rb-4.1.0&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D'),
(2, 'Δελφοί', 'Delphi', 'Ιστορικός', 'Βουνό', 'Παντός Καιρού', 'All Year', 45, 'Ο ομφαλός της γης, μέσα στο βουνό, ιδανικός για λάτρεις της αρχαιότητας.', 'The navel of the earth, nestled in the mountains, ideal for ancient history lovers.', '📍 <b>Αξιοθέατα:</b> Ναός Απόλλωνα, Μαντείο.<br>🍽️ <b>Γεύσεις:</b> Ντόπια κρέατα.<br>💡 <b>Tip:</b> Συνδυάστε το με μια βόλτα στην Αράχωβα.', '📍 <b>Sights:</b> Temple of Apollo, Oracle.<br>🍽️ <b>Food:</b> Local meats.<br>💡 <b>Tip:</b> Combine it with a trip to Arachova.', 'https://media.istockphoto.com/id/157116129/photo/sanctuary-of-athena-pronaia-delphi-greece.jpg?s=2048x2048&w=is&k=20&c=LsBbmgmt-LEJivvKO9IkLtWZr9YVno9or0Og7gEzWOw='),
(3, 'Μυκήνες & Ναύπλιο', 'Mycenae & Nafplio', 'Ιστορικός', 'Πόλη', 'Παντός Καιρού', 'All Year', 55, 'Συνδυασμός του ιστορικού Ναυπλίου και των αρχαίων Μυκηνών δίπλα στη θάλασσα.', 'A combination of historic Nafplio and ancient Mycenae by the sea.', '📍 <b>Αξιοθέατα:</b> Παλαμήδι, Πύλη Λεόντων.<br>🍽️ <b>Γεύσεις:</b> Φρέσκο ψάρι, Παγωτό.<br>💡 <b>Tip:</b> Ανεβείτε τα 999 σκαλιά στο Παλαμήδι!', '📍 <b>Sights:</b> Palamidi, Lion Gate.<br>🍽️ <b>Food:</b> Fresh fish, Gelato.<br>💡 <b>Tip:</b> Climb the 999 steps of Palamidi fortress!', 'https://www.geografikoi.gr/wp-content/uploads/2023/06/pou-na-meinw-ston-nauplio.jpg'),
(4, 'Ηράκλειο (Κνωσός)', 'Heraklion (Knossos)', 'Ιστορικός', 'Πόλη', 'Καλοκαίρι', 'Summer', 50, 'Το κέντρο του Μινωικού πολιτισμού, συνδυάζει πλούσια ιστορία και αστική ζωή.', 'The center of Minoan civilization, combining rich history and urban life.', '📍 <b>Αξιοθέατα:</b> Ανάκτορο Κνωσού, Κούλες.<br>🍽️ <b>Γεύσεις:</b> Ντάκος, Χοχλιοί.<br>💡 <b>Tip:</b> Επισκεφθείτε το Αρχαιολογικό Μουσείο.', '📍 <b>Sights:</b> Knossos Palace, Koules.<br>🍽️ <b>Food:</b> Dakos, Snails.<br>💡 <b>Tip:</b> Visit the Archaeological Museum.', 'https://images.unsplash.com/photo-1660806886383-d8558af05201?q=80&w=1170&auto=format&fit=crop&ixlib=rb-4.1.0&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D'),
(5, 'Ρόδος (Παλιά Πόλη)', 'Rhodes (Old Town)', 'Ιστορικός', 'Θάλασσα', 'Καλοκαίρι', 'Summer', 65, 'Η εντυπωσιακή μεσαιωνική πόλη των Ιπποτών δίπλα στα καταγάλανα νερά.', 'The impressive medieval City of Knights by the crystal clear waters.', '📍 <b>Αξιοθέατα:</b> Παλάτι Μεγάλου Μαγίστρου, Λίνδος.<br>🍽️ <b>Γεύσεις:</b> Πιταρούδια, Μελεκούνι.<br>💡 <b>Tip:</b> Περπατήστε στην Οδό των Ιπποτών το σούρουπο.', '📍 <b>Sights:</b> Palace of the Grand Master, Lindos.<br>🍽️ <b>Food:</b> Pitaroudia, Melekouni.<br>💡 <b>Tip:</b> Walk the Street of the Knights at dusk.', 'https://images.unsplash.com/photo-1547977466-395ea3261372?q=80&w=1074&auto=format&fit=crop&ixlib=rb-4.1.0&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D'),
(6, 'Σαντορίνη', 'Santorini', 'Ρομαντικός', 'Θάλασσα', 'Καλοκαίρι', 'Summer', 90, 'Ο απόλυτος ρομαντικός προορισμός παγκοσμίως με μαγευτική θέα στη θάλασσα.', 'The ultimate global romantic destination with breathtaking sea views.', '📍 <b>Αξιοθέατα:</b> Ηλιοβασίλεμα Οίας, Ηφαίστειο.<br>🍽️ <b>Γεύσεις:</b> Φάβα, Vinsanto.<br>💡 <b>Tip:</b> Κλείστε τραπέζι νωρίς για το ηλιοβασίλεμα.', '📍 <b>Sights:</b> Oia Sunset, Volcano.<br>🍽️ <b>Food:</b> Fava, Vinsanto wine.<br>💡 <b>Tip:</b> Book a table early for the sunset.', 'https://plus.unsplash.com/premium_photo-1661964149725-fbf14eabd38c?q=80&w=1170&auto=format&fit=crop&ixlib=rb-4.1.0&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D'),
(7, 'Μονεμβασιά', 'Monemvasia', 'Ρομαντικός', 'Θάλασσα', 'Παντός Καιρού', 'All Year', 55, 'Μεσαιωνική καστροπολιτεία, ο απόλυτος ρομαντικός προορισμός της Πελοποννήσου.', 'A medieval castle town, the absolute romantic destination of the Peloponnese.', '📍 <b>Αξιοθέατα:</b> Κάτω Πόλη, Ναός Αγίας Σοφίας.<br>🍽️ <b>Γεύσεις:</b> Αμυγδαλωτά.<br>💡 <b>Tip:</b> Απαγορεύονται τα αυτοκίνητα μέσα στο Κάστρο.', '📍 <b>Sights:</b> Lower Town, Hagia Sophia.<br>🍽️ <b>Food:</b> Almond sweets.<br>💡 <b>Tip:</b> Cars are prohibited inside the Castle.', 'https://images.unsplash.com/photo-1621710490963-31130dba2419?q=80&w=1332&auto=format&fit=crop&ixlib=rb-4.1.0&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D'),
(8, 'Αράχωβα', 'Arachova', 'Ρομαντικός', 'Βουνό', 'Χειμώνας', 'Winter', 70, 'Το απόλυτο χειμερινό θέρετρο, ιδανικό για ζευγάρια δίπλα στο τζάκι.', 'The ultimate winter resort, perfect for couples by the fireplace.', '📍 <b>Αξιοθέατα:</b> Ρολόι, Χιονοδρομικό Παρνασσού.<br>🍽️ <b>Γεύσεις:</b> Φορμαέλα.<br>💡 <b>Tip:</b> Ιδανική για σκι και ζεστή σοκολάτα.', '📍 <b>Sights:</b> The Clock Tower, Parnassos Ski Center.<br>🍽️ <b>Food:</b> Formaela cheese.<br>💡 <b>Tip:</b> Perfect for skiing and hot chocolate.', 'https://www.geografikoi.gr/wp-content/uploads/2023/01/pnm-arachova.jpg'),
(9, 'Νυμφαίο', 'Nymfaio', 'Ρομαντικός', 'Βουνό', 'Χειμώνας', 'Winter', 45, 'Ένα από τα δέκα ομορφότερα χωριά της Ευρώπης, γραφικό και παραμυθένιο.', 'One of the ten most beautiful villages in Europe, picturesque and fairytale-like.', '📍 <b>Αξιοθέατα:</b> Καταφύγιο Αρκούδας (Αρκτούρος).<br>🍽️ <b>Γεύσεις:</b> Ντόπιο κρασί, Κυνήγι.<br>💡 <b>Tip:</b> Το χωριό διατηρεί άθικτη την αρχιτεκτονική του.', '📍 <b>Sights:</b> Bear Sanctuary (Arcturos).<br>🍽️ <b>Food:</b> Local wine, Game meat.<br>💡 <b>Tip:</b> The village maintains its intact architecture.', 'https://www.travel.gr/wp-content/uploads/webp/2023/02/Nymf-vl_front-2048x1364.webp'),
(10, 'Πάργα', 'Parga', 'Ρομαντικός', 'Θάλασσα', 'Καλοκαίρι', 'Summer', 55, 'Γραφική πόλη που θυμίζει νησί, με στενά σοκάκια και ρομαντική ατμόσφαιρα.', 'A picturesque town that feels like an island, with narrow streets and romantic vibes.', '📍 <b>Αξιοθέατα:</b> Κάστρο Πάργας, Νησάκι Παναγιάς.<br>🍽️ <b>Γεύσεις:</b> Φρέσκα θαλασσινά.<br>💡 <b>Tip:</b> Απολαύστε τη θέα από το κάστρο.', '📍 <b>Sights:</b> Castle of Parga, Panagia Islet.<br>🍽️ <b>Food:</b> Fresh seafood.<br>💡 <b>Tip:</b> Enjoy the view from the castle.', 'https://e498h76z5mp.exactdn.com/wp-content/uploads/2016/10/Parga.jpg?quality=65'),
(11, 'Χανιά', 'Chania', 'Οικογενειακός', 'Θάλασσα', 'Καλοκαίρι', 'Summer', 65, 'Ιδανικό για οικογένειες, με υπέροχες αμμώδεις παραλίες, κρητική παράδοση και ασφάλεια.', 'Ideal for families, with beautiful sandy beaches, Cretan tradition, and safety.', '📍 <b>Αξιοθέατα:</b> Ενετικό Λιμάνι, Ελαφονήσι.<br>🍽️ <b>Γεύσεις:</b> Χανιώτικο Μπουρέκι.<br>💡 <b>Tip:</b> Ενοικιάστε αυτοκίνητο για τις παραλίες.', '📍 <b>Sights:</b> Venetian Harbor, Elafonissi.<br>🍽️ <b>Food:</b> Chaniotiko Boureki.<br>💡 <b>Tip:</b> Rent a car for the beaches.', 'https://www.geografikoi.gr/wp-content/uploads/2023/03/5-meres-sta-chania-1.jpg'),
(12, 'Χαλκιδική', 'Halkidiki', 'Οικογενειακός', 'Θάλασσα', 'Καλοκαίρι', 'Summer', 60, 'Ρηχές θάλασσες, μεγάλα resort και ατελείωτες επιλογές για γονείς και παιδιά.', 'Shallow waters, large resorts, and endless options for parents and kids.', '📍 <b>Αξιοθέατα:</b> Σπήλαιο Πετραλώνων, Κασσάνδρα.<br>🍽️ <b>Γεύσεις:</b> Μέλι, Ελιές.<br>💡 <b>Tip:</b> Ιδανική επιλογή το πρώτο \"πόδι\" για οικογένειες.', '📍 <b>Sights:</b> Petralona Cave, Kassandra.<br>🍽️ <b>Food:</b> Honey, Olives.<br>💡 <b>Tip:</b> The first \"leg\" is perfect for families.', 'https://plus.unsplash.com/premium_photo-1664302218292-3ca7f6f08902?q=80&w=1332&auto=format&fit=crop&ixlib=rb-4.1.0&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D'),
(13, 'Καρπενήσι', 'Karpenisi', 'Οικογενειακός', 'Βουνό', 'Χειμώνας', 'Winter', 45, 'Οικογενειακός προορισμός στη φύση, ιδανικός για βουνό, σκι και καθαρό αέρα.', 'A family nature destination, ideal for mountains, skiing, and fresh air.', '📍 <b>Αξιοθέατα:</b> Μονή Προυσού, Χιονοδρομικό.<br>🍽️ <b>Γεύσεις:</b> Λουκάνικα Ευρυτανίας.<br>💡 <b>Tip:</b> Εξαιρετικά μονοπάτια για πεζοπορία.', '📍 <b>Sights:</b> Proussos Monastery, Ski Resort.<br>🍽️ <b>Food:</b> Evrytania Sausages.<br>💡 <b>Tip:</b> Excellent hiking trails.', 'https://as2.ftcdn.net/v2/jpg/03/97/46/95/1000_F_397469574_23X34beQb6rzaE0UXkq6OaMx9mNHgNqY.jpg'),
(14, 'Καλάβρυτα', 'Kalavryta', 'Ιστορικός', 'Βουνό', 'Χειμώνας', 'Winter', 45, 'Ιστορικό μέρος με τον θρυλικό Οδοντωτό σιδηρόδρομο, τέλειο για οικογενειακή εκδρομή.', 'Historic place with the legendary Odontotos railway, perfect for a family trip.', '📍 <b>Αξιοθέατα:</b> Οδοντωτός, Μέγα Σπήλαιο.<br>🍽️ <b>Γεύσεις:</b> Φέτα, Χυλοπίτες.<br>💡 <b>Tip:</b> Η διαδρομή με τον Οδοντωτό είναι μοναδική.', '📍 <b>Sights:</b> Odontotos Rack Railway, Mega Spilaio.<br>🍽️ <b>Food:</b> Feta cheese, Pasta.<br>💡 <b>Tip:</b> The Odontotos ride is unique.', 'https://www.travel.gr/wp-content/uploads/2024/03/kalavryta-2-2048x1365.jpg'),
(15, 'Τρίκαλα', 'Trikala', 'Οικογενειακός', 'Πόλη', 'Χειμώνας', 'Winter', 45, 'Μαγικός προορισμός για οικογένειες, ειδικά την εορταστική περίοδο (Μύλος Ξωτικών).', 'A magical destination for families, especially during the festive season.', '📍 <b>Αξιοθέατα:</b> Μύλος των Ξωτικών, Φρούριο.<br>🍽️ <b>Γεύσεις:</b> Λουκάνικα Τρικάλων.<br>💡 <b>Tip:</b> Πόλη απόλυτα φιλική για ποδήλατο.', '📍 <b>Sights:</b> Mill of the Elves, Fortress.<br>🍽️ <b>Food:</b> Trikala Sausages.<br>💡 <b>Tip:</b> Extremely bicycle-friendly city.', 'https://visitthessaly.gr/sites/default/files/styles/og_image/public/2025-01/D-Trikala%20%281%29.jpg?itok=IHK7LHTt'),
(16, 'Μύκονος', 'Mykonos', 'Διασκέδαση', 'Θάλασσα', 'Καλοκαίρι', 'Summer', 110, 'Ο κορυφαίος προορισμός για έντονη παραθαλάσσια νυχτερινή ζωή και πολυτέλεια.', 'The top destination for intense coastal nightlife and luxury.', '📍 <b>Αξιοθέατα:</b> Μικρή Βενετία, Ανεμόμυλοι.<br>🍽️ <b>Γεύσεις:</b> Κοπανιστή.<br>💡 <b>Tip:</b> Η νυχτερινή ζωή ξεκινά μετά τα μεσάνυχτα.', '📍 <b>Sights:</b> Little Venice, Windmills.<br>🍽️ <b>Food:</b> Kopanisti cheese.<br>💡 <b>Tip:</b> Nightlife starts after midnight.', 'https://www.travel.gr/wp-content/uploads/2024/08/mykonos2-scaled.jpg'),
(17, 'Πάρος', 'Paros', 'Διασκέδαση', 'Θάλασσα', 'Καλοκαίρι', 'Summer', 75, 'Νεανικός προορισμός με έντονη ζωή στα σοκάκια της Νάουσας και όμορφες παραλίες.', 'A youthful destination with vibrant life in the alleys of Naoussa and beautiful beaches.', '📍 <b>Αξιοθέατα:</b> Νάουσα, Κολυμπήθρες.<br>🍽️ <b>Γεύσεις:</b> Γούνα (λιαστό ψάρι).<br>💡 <b>Tip:</b> Πιείτε το ποτό σας στο λιμανάκι της Νάουσας.', '📍 <b>Sights:</b> Naoussa, Kolymbithres.<br>🍽️ <b>Food:</b> Gouna (sun-dried fish).<br>💡 <b>Tip:</b> Have a drink at the small port of Naoussa.', 'https://www.visitgreece.gr/files/merakos_02_paros-naousa_1743x752.jpg'),
(18, 'Ίος', 'Ios', 'Διασκέδαση', 'Θάλασσα', 'Καλοκαίρι', 'Summer', 55, 'Το νησί της νεολαίας, φημισμένο για τα ατελείωτα πάρτι και την ελευθερία.', 'The island of youth, famous for endless parties and freedom.', '📍 <b>Αξιοθέατα:</b> Μαγγανάρι, Τάφος Ομήρου.<br>🍽️ <b>Γεύσεις:</b> Νιώτικο τυρί.<br>💡 <b>Tip:</b> Η Χώρα είναι το κέντρο του πάρτι.', '📍 <b>Sights:</b> Magganari, Tomb of Homer.<br>🍽️ <b>Food:</b> Niotiko cheese.<br>💡 <b>Tip:</b> Chora is the center of the party.', 'https://www.newsbeast.gr/files/1/2020/07/KLIK_shutterstock_59468536.jpg'),
(19, 'Σκιάθος', 'Skiathos', 'Διασκέδαση', 'Θάλασσα', 'Καλοκαίρι', 'Summer', 60, 'Κοσμοπολίτικο νησί των Σποράδων με έντονη νυχτερινή ζωή και καταπράσινα τοπία.', 'Cosmopolitan island of the Sporades with intense nightlife and lush landscapes.', '📍 <b>Αξιοθέατα:</b> Κουκουναριές, Μπούρτζι.<br>🍽️ <b>Γεύσεις:</b> Αμυγδαλωτά.<br>💡 <b>Tip:</b> Εξερευνήστε το νησί με καραβάκι.', '📍 <b>Sights:</b> Koukounaries, Bourtzi.<br>🍽️ <b>Food:</b> Almond sweets.<br>💡 <b>Tip:</b> Explore the island by boat.', 'https://visitthessaly.gr/sites/default/files/styles/og_image/public/2025-01/D-Skiathos-%281%29.jpg?itok=wHJDs60h'),
(20, 'Θεσσαλονίκη', 'Thessaloniki', 'Διασκέδαση', 'Πόλη', 'Παντός Καιρού', 'All Year', 55, 'Η πρωτεύουσα της διασκέδασης και της γαστρονομίας, με έντονη ζωή όλο το 24ωρο.', 'The capital of entertainment and gastronomy, with vibrant life 24/7.', '📍 <b>Αξιοθέατα:</b> Λευκός Πύργος, Λαδάδικα.<br>🍽️ <b>Γεύσεις:</b> Μπουγάτσα, Κουλούρι.<br>💡 <b>Tip:</b> Ιδανική για φοιτητές και νέους.', '📍 <b>Sights:</b> White Tower, Ladadika.<br>🍽️ <b>Food:</b> Bougatsa, Koulouri.<br>💡 <b>Tip:</b> Perfect for students and youth.', 'https://media-cdn.tripadvisor.com/media/photo-s/19/86/41/82/thessaloniki-greece-s.jpg'),
(21, 'Ζαγοροχώρια', 'Zagorochoria', 'Ρομαντικός', 'Βουνό', 'Χειμώνας', 'Winter', 50, 'Πέτρινα παραδοσιακά χωριά μέσα στο βουνό και το Φαράγγι του Βίκου, ιδανικά για εξερεύνηση.', 'Traditional stone villages in the mountains and the Vikos Gorge, ideal for exploration.', '📍 <b>Αξιοθέατα:</b> Φαράγγι Βίκου, Πέτρινα Γεφύρια.<br>🍽️ <b>Γεύσεις:</b> Ζαγορίσια Πίτα.<br>💡 <b>Tip:</b> Απαιτείται αυτοκίνητο για τις μετακινήσεις.', '📍 <b>Sights:</b> Vikos Gorge, Stone Bridges.<br>🍽️ <b>Food:</b> Zagorisian Pie.<br>💡 <b>Tip:</b> A car is required for getting around.', 'https://exploringgreece.tv/wp-content/uploads/2023/12/zagorochoria-ipeiros-mikro-papigko-megalo-papigko-choria-axiotheata.jpg'),
(22, 'Μετέωρα', 'Meteora', 'Φύση', 'Βουνό', 'Παντός Καιρού', 'All Year', 50, 'Εντυπωσιακοί βράχοι και μοναστήρια που προσφέρουν γαλήνη, δέος και μονοπάτια πεζοπορίας.', 'Impressive rocks and monasteries offering peace, awe, and hiking trails.', '📍 <b>Αξιοθέατα:</b> Ιερές Μονές, Καλαμπάκα.<br>🍽️ <b>Γεύσεις:</b> Σουβλάκι Καλαμπάκας.<br>💡 <b>Tip:</b> Η θέα το ηλιοβασίλεμα είναι μαγική.', '📍 <b>Sights:</b> Holy Monasteries, Kalambaka.<br>🍽️ <b>Food:</b> Kalambaka Souvlaki.<br>💡 <b>Tip:</b> The sunset view is magical.', 'https://www.greeka.com/photos/thessaly/meteora/hero/meteora-3-1920.jpg'),
(23, 'Πήλιο', 'Pelion', 'Ρομαντικός', 'Βουνό', 'Παντός Καιρού', 'All Year', 50, 'Ο τέλειος συνδυασμός βουνού και θάλασσας, γεμάτο δάση και γραφικά μονοπάτια.', 'The perfect combination of mountain and sea, full of forests and scenic trails.', '📍 <b>Αξιοθέατα:</b> Τσαγκαράδα, Μακρινίτσα.<br>🍽️ <b>Γεύσεις:</b> Σπετζοφάι.<br>💡 <b>Tip:</b> Μοναδικά πετρόχτιστα μονοπάτια.', '📍 <b>Sights:</b> Tsagarada, Makrinitsa.<br>🍽️ <b>Food:</b> Spetzofai.<br>💡 <b>Tip:</b> Unique stone-paved trails.', 'https://www.kathimerini.gr/wp-content/uploads/2022/07/shutterstock_2078128354.jpg?v=1656935603'),
(24, 'Λίμνη Πλαστήρα', 'Lake Plastiras', 'Οικογενειακός', 'Βουνό', 'Παντός Καιρού', 'All Year', 45, 'Υπέροχο αλπικό τοπίο, προσφέρει δραστηριότητες όπως καγιάκ, ποδήλατο και ιππασία.', 'Wonderful alpine landscape offering activities like kayaking, cycling, and horseback riding.', '📍 <b>Αξιοθέατα:</b> Φράγμα, Βοτανικός Κήπος.<br>🍽️ <b>Γεύσεις:</b> Πέστροφα ψητή.<br>💡 <b>Tip:</b> Εξαιρετικό για ποδήλατο βουνού.', '📍 <b>Sights:</b> The Dam, Botanical Garden.<br>🍽️ <b>Food:</b> Grilled trout.<br>💡 <b>Tip:</b> Excellent for mountain biking.', 'https://www.travel.gr/wp-content/uploads/2021/09/plastira-fragma-2-1.jpg'),
(25, 'Σαμοθράκη', 'Samothrace', 'Φύση', 'Θάλασσα', 'Καλοκαίρι', 'Summer', 40, 'Καταρράκτες, βάθρες και παρθένα φύση. Ο απόλυτος εναλλακτικός προορισμός.', 'Waterfalls, natural pools, and pristine nature. The ultimate alternative destination.', '📍 <b>Αξιοθέατα:</b> Βάθρες, Ιερό Μεγάλων Θεών.<br>🍽️ <b>Γεύσεις:</b> Ντόπιο κατσικάκι.<br>💡 <b>Tip:</b> Προετοιμαστείτε για πεζοπορία!', '📍 <b>Sights:</b> Vathres (pools), Sanctuary of Great Gods.<br>🍽️ <b>Food:</b> Local roasted goat.<br>💡 <b>Tip:</b> Prepare for hiking!', 'https://fastferries.com.gr/wp-content/uploads/2025/05/samothraki-xwra.jpg'),
(26, 'Εύβοια (Χαλκίδα)', 'Evia (Xalkida)', 'Οικογενειακός', 'Θάλασσα', 'Καλοκαίρι', 'Summer', 45, 'Τεράστια ακτογραμμή, οικονομική πρόσβαση χωρίς πλοίο και γραφικά χωριά.', 'Huge coastline, economical access without a ferry, and picturesque villages.', '📍 <b>Αξιοθέατα:</b> Χαλκίδα, Παραλία Χιλιαδού.<br>🍽️ <b>Γεύσεις:</b> Φρέσκο ψάρι, τυροπιτάρι.<br>💡 <b>Tip:</b> Εξερευνήστε τη βόρεια πλευρά για απίστευτο πράσινο.', '📍 <b>Sights:</b> Chalkida, Chiliadou beach.<br>🍽️ <b>Food:</b> Fresh fish, cheese pies.<br>💡 <b>Tip:</b> Explore the northern side for lush nature.', 'https://www.visitgreece.gr/images/1743x752/jpg/files/s_1524377990_evia-chalkida_1743x752.jpg'),
(27, 'Ναύπακτος', 'Nafpaktos', 'Ρομαντικός', 'Πόλη', 'Παντός Καιρού', 'All Year', 45, 'Πανέμορφο ενετικό λιμάνι, ιδανικό για ζευγάρια και οικονομικές αποδράσεις.', 'Beautiful Venetian harbor, ideal for couples and budget getaways.', '📍 <b>Αξιοθέατα:</b> Ενετικό Λιμάνι, Κάστρο.<br>🍽️ <b>Γεύσεις:</b> Παραδοσιακά γλυκά.<br>💡 <b>Tip:</b> Η βόλτα στο κάστρο έχει τέλεια θέα.', '📍 <b>Sights:</b> Venetian Harbor, Castle.<br>🍽️ <b>Food:</b> Traditional sweets.<br>💡 <b>Tip:</b> The castle walk offers perfect views.', 'https://www.travel.gr/wp-content/uploads/2022/02/nafpaktos-kentriki-2048x1535.jpg'),
(28, 'Ικαρία', 'Ikaria', 'Φύση', 'Θάλασσα', 'Καλοκαίρι', 'Summer', 45, 'Το νησί της μακροζωίας και των πανηγυριών. Απόλυτα εναλλακτικός και φθηνός προορισμός.', 'The island of longevity and traditional festivals. The ultimate alternative destination.', '📍 <b>Αξιοθέατα:</b> Σεϋχέλλες, Χριστός Ραχών.<br>🍽️ <b>Γεύσεις:</b> Κατσικάκι, Ντόπιο Κρασί.<br>💡 <b>Tip:</b> Ο χρόνος εδώ κυλάει αλλιώς!', '📍 <b>Sights:</b> Seychelles beach, Christos Raches.<br>🍽️ <b>Food:</b> Local goat, Wine.<br>💡 <b>Tip:</b> Time flows differently here!', 'https://www.shutterstock.com/image-photo/agios-kirikos-village-capital-ikaria-260nw-2361047379.jpg'),
(29, 'Λιτόχωρο & Όλυμπος', 'Litochoro & Olympus', 'Φύση', 'Βουνό', 'Παντός Καιρού', 'All Year', 45, 'Στους πρόποδες του Ολύμπου, συνδυάζει βουνό και θάλασσα με ελάχιστο κόστος.', 'At the foothills of Olympus, combining mountain and sea at minimal cost.', '📍 <b>Αξιοθέατα:</b> Φαράγγι Ενιπέα, Πριόνια.<br>🍽️ <b>Γεύσεις:</b> Ντόπια κρέατα.<br>💡 <b>Tip:</b> Ιδανικό για λάτρεις της πεζοπορίας.', '📍 <b>Sights:</b> Enipeas Gorge, Prionia.<br>🍽️ <b>Food:</b> Local meats.<br>💡 <b>Tip:</b> Ideal for hiking lovers.', 'https://cf.bstatic.com/xdata/images/hotel/max1024x768/411693621.jpg?k=bc4d1d5a5b0fe44f31315bb3d9c093de884eea0b6f66e7da5cbdcbc8a6ec9661&o='),
(30, 'Λεωνίδιο', 'Leonidio', 'Φύση', 'Βουνό', 'Παντός Καιρού', 'All Year', 45, 'Εντυπωσιακοί κόκκινοι βράχοι και παραδοσιακή αρχιτεκτονική στην Αρκαδία.', 'Impressive red rocks and traditional architecture in Arcadia.', '📍 <b>Αξιοθέατα:</b> Κόκκινος Βράχος, Πλάκα.<br>🍽️ <b>Γεύσεις:</b> Τσακώνικη Μελιτζάνα.<br>💡 <b>Tip:</b> Κορυφαίος προορισμός για αναρρίχηση.', '📍 <b>Sights:</b> Red Rock, Plaka.<br>🍽️ <b>Food:</b> Tsakonian Eggplant.<br>💡 <b>Tip:</b> Top destination for rock climbing.', 'https://www.travel.gr/wp-content/uploads/2025/07/Festival-Melitzazz-2025-18.jpg'),
(31, 'Κέρκυρα', 'Corfu', 'Ιστορικός', 'Θάλασσα', 'Καλοκαίρι', 'Summer', 65, 'Το στολίδι του Ιονίου με την αρχοντική ενετική αρχιτεκτονική.', 'The jewel of the Ionian sea with Venetian architecture.', '📍 <b>Αξιοθέατα:</b> Αχίλλειο, Ποντικονήσι.<br>🍽️ <b>Γεύσεις:</b> Παστιτσάδα.', '📍 <b>Sights:</b> Achilleion, Pontikonissi.<br>🍽️ <b>Food:</b> Pastitsada.', 'https://images.ferryhopper.com/destination/corfu-old-town-castle.jpeg'),
(32, 'Μήλος', 'Milos', 'Ρομαντικός', 'Θάλασσα', 'Καλοκαίρι', 'Summer', 75, 'Το νησί των χρωμάτων. Μοναδικά σεληνιακά τοπία και κρυστάλλινα νερά.', 'The island of colors. Unique volcanic landscapes.', '📍 <b>Αξιοθέατα:</b> Σαρακήνικο, Κλέφτικο.<br>🍽️ <b>Γεύσεις:</b> Πιταράκια.', '📍 <b>Sights:</b> Sarakiniko, Kleftiko.<br>🍽️ <b>Food:</b> Pitarakia.', 'https://www.travel.gr/wp-content/uploads/2022/04/milos-scaled.jpg'),
(33, 'Σύρος', 'Syros', 'Ρομαντικός', 'Πόλη', 'Παντός Καιρού', 'All Year', 55, 'Αρχοντική και κοσμοπολίτικη, η πρωτεύουσα των Κυκλάδων με την εντυπωσιακή Ερμούπολη.', 'Noble and cosmopolitan, the capital of the Cyclades.', '📍 <b>Αξιοθέατα:</b> Άνω Σύρος, Πλατεία Μιαούλη.<br>🍽️ <b>Γεύσεις:</b> Λουκούμια, Χαλβαδόπιτες.<br>💡 <b>Tip:</b> Περπατήστε στα σοκάκια της Άνω Σύρου το ηλιοβασίλεμα.', '📍 <b>Sights:</b> Ano Syros, Miaouli Square.<br>🍽️ <b>Food:</b> Loukoumia.<br>💡 <b>Tip:</b> Walk the alleys of Ano Syros at sunset.', 'https://www.travel.gr/wp-content/uploads/2022/08/shutterstock_1350427844-scaled.jpg'),
(34, 'Ιωάννινα', 'Ioannina', 'Φύση', 'Πόλη', 'Παντός Καιρού', 'All Year', 45, 'Η πόλη των θρύλων δίπλα στην πανέμορφη λίμνη Παμβώτιδα, γεμάτη ζωή και ιστορία.', 'The city of legends next to the beautiful lake Pamvotis.', '📍 <b>Αξιοθέατα:</b> Νησάκι Λίμνης, Κάστρο Ιωαννίνων.<br>🍽️ <b>Γεύσεις:</b> Βατραχοπόδαρα, Μπακλαβάς.<br>💡 <b>Tip:</b> Κάντε το γύρο της λίμνης με ποδήλατο.', '📍 <b>Sights:</b> Lake Island, Castle.<br>🍽️ <b>Food:</b> Frog legs, Baklava.<br>💡 <b>Tip:</b> Cycle around the lake.', 'https://www.ekdromi.gr/cdn-cgi/image/w=1220,h=610,fit=cover,f=webp/public/images/upload/cities/ioannina_coverb53b4.jpg'),
(35, 'Μέτσοβο', 'Metsovo', 'Οικογενειακός', 'Βουνό', 'Χειμώνας', 'Winter', 50, 'Ορεινός παραδοσιακός οικισμός με πλούσια γαστρονομία και γραφικά τοπία.', 'Traditional mountain village with rich gastronomy.', '📍 <b>Αξιοθέατα:</b> Πινακοθήκη Τοσίτσα, Κατώγι.<br>🍽️ <b>Γεύσεις:</b> Τυρί Μετσοβόνε, Κοντοσούβλι.<br>💡 <b>Tip:</b> Εξαιρετικό μέρος για αγορά τοπικών τυριών και κρασιών.', '📍 <b>Sights:</b> Tositsa Gallery.<br>🍽️ <b>Food:</b> Metsovone cheese.<br>💡 <b>Tip:</b> Great place to buy local wines.', 'https://www.travel.gr/wp-content/uploads/2025/01/metsovo-1-2048x1536.jpg'),
(36, 'Κεφαλονιά', 'Kefalonia', 'Οικογενειακός', 'Θάλασσα', 'Καλοκαίρι', 'Summer', 60, 'Το μεγαλύτερο νησί του Ιονίου, με σμαραγδένια νερά και καταπράσινη φύση.', 'The largest Ionian island, with emerald waters.', '📍 <b>Αξιοθέατα:</b> Μύρτος, Σπήλαιο Μελισσάνης.<br>🍽️ <b>Γεύσεις:</b> Κρεατόπιτα, Κρασί Ρομπόλα.<br>💡 <b>Tip:</b> Απαιτείται αυτοκίνητο λόγω των μεγάλων αποστάσεων.', '📍 <b>Sights:</b> Myrtos, Melissani Cave.<br>🍽️ <b>Food:</b> Meat pie, Robola wine.<br>💡 <b>Tip:</b> A car is required due to large distances.', 'https://www.travel.gr/wp-content/uploads/2025/07/KEFALONIA-AVIS-20-2048x1536.jpg'),
(37, 'Ζάκυνθος', 'Zakynthos', 'Διασκέδαση', 'Θάλασσα', 'Καλοκαίρι', 'Summer', 55, 'Παγκοσμίως διάσημη για το Ναυάγιο και την έντονη νυχτερινή ζωή.', 'World famous for the Shipwreck beach and nightlife.', '📍 <b>Αξιοθέατα:</b> Ναυάγιο, Γαλάζιες Σπηλιές.<br>🍽️ <b>Γεύσεις:</b> Μαντολάτο, Φριτούρα.<br>💡 <b>Tip:</b> Κάντε βαρκάδα για να δείτε τις χελώνες Caretta Caretta.', '📍 <b>Sights:</b> Shipwreck, Blue Caves.<br>🍽️ <b>Food:</b> Mantolato.<br>💡 <b>Tip:</b> Take a boat to see the turtles.', 'https://www.travel.gr/wp-content/uploads/2021/07/Zakynthos-Unsplash-Julian-Timmerman-1-2048x1367.jpg'),
(38, 'Λευκάδα', 'Lefkada', 'Οικογενειακός', 'Θάλασσα', 'Καλοκαίρι', 'Summer', 55, 'Προσβάσιμη οδικώς, προσφέρει μερικές από τις εντυπωσιακότερες παραλίες της Μεσογείου.', 'Accessible by car, offering some of the best beaches.', '📍 <b>Αξιοθέατα:</b> Πόρτο Κατσίκι, Εγκρεμνοί.<br>🍽️ <b>Γεύσεις:</b> Σαλάμι αέρος, Φακές Εγκλουβής.<br>💡 <b>Tip:</b> Προσοχή στα κύματα των δυτικών παραλιών.', '📍 <b>Sights:</b> Porto Katsiki, Egremni.<br>🍽️ <b>Food:</b> Air salami, Lentils.<br>💡 <b>Tip:</b> Beware of the waves on western beaches.', 'https://www.travel.gr/wp-content/uploads/2023/05/lefkada-marine-2048x1364.jpg'),
(39, 'Αλόννησος', 'Alonissos', 'Φύση', 'Θάλασσα', 'Καλοκαίρι', 'Summer', 45, 'Ο παράδεισος της γαλήνης και το σπίτι της μεσογειακής φώκιας Monachus monachus.', 'The paradise of peace and home to the Mediterranean seal.', '📍 <b>Αξιοθέατα:</b> Θαλάσσιο Πάρκο, Παλιά Χώρα.<br>🍽️ <b>Γεύσεις:</b> Τονάκι, Τυρόπιτα στριφτή.<br>💡 <b>Tip:</b> Κλείστε εκδρομή με καΐκι στο Θαλάσσιο Πάρκο.', '📍 <b>Sights:</b> Marine Park, Old Chora.<br>🍽️ <b>Food:</b> Tuna, Cheese pie.<br>💡 <b>Tip:</b> Book a boat trip to the Marine Park.', 'https://www.travel.gr/wp-content/uploads/2021/09/Patitiri_ZDG_7709.jpg'),
(40, 'Κως', 'Kos', 'Οικογενειακός', 'Θάλασσα', 'Καλοκαίρι', 'Summer', 50, 'Το νησί του Ιπποκράτη, ιδανικό για ποδήλατο, με μεγάλες αμμώδεις παραλίες.', 'The island of Hippocrates, ideal for cycling.', '📍 <b>Αξιοθέατα:</b> Ασκληπιείο, Κάστρο Νεραντζιάς.<br>🍽️ <b>Γεύσεις:</b> Κρασοτύρι, Γλυκό ντοματάκι.<br>💡 <b>Tip:</b> Νοικιάστε ποδήλατο, το νησί είναι επίπεδο και γεμάτο ποδηλατόδρομους.', '📍 <b>Sights:</b> Asklepieion, Castle.<br>🍽️ <b>Food:</b> Wine cheese.<br>💡 <b>Tip:</b> Rent a bike, the island is flat.', 'https://files.madamefigaro.gr/Content/ImagesDatabase/p/1455x819/crop/both/0d/0d697e0bb4074b73a9b48c39d04d5604.jpg?quality=80&404=default&v=4'),
(41, 'Πάτρα', 'Patras', 'Διασκέδαση', 'Πόλη', 'Παντός Καιρού', 'All Year', 45, 'Φοιτητούπολη με έντονη ζωή, γνωστή για το μεγαλύτερο Καρναβάλι της χώρας.', 'Student city with vibrant life, known for its Carnival.', '📍 <b>Αξιοθέατα:</b> Γέφυρα Ρίου-Αντιρρίου, Κάστρο.<br>🍽️ <b>Γεύσεις:</b> Τεντούρα, Μαυροδάφνη.<br>💡 <b>Tip:</b> Ο πεζόδρομος της Ρήγα Φεραίου είναι γεμάτος υπέροχα καφέ.', '📍 <b>Sights:</b> Rio-Antirrio Bridge, Castle.<br>🍽️ <b>Food:</b> Tentoura, Mavrodaphne wine.<br>💡 <b>Tip:</b> Riga Fereou street is full of cafes.', 'https://www.travel.gr/wp-content/uploads/2024/02/patra-skalakia-agiou-nikolaou-2048x1365.jpg'),
(42, 'Επίδαυρος', 'Epidaurus', 'Ιστορικός', 'Θάλασσα', 'Καλοκαίρι', 'Summer', 45, 'Συνδυάζει την εκπληκτική ιστορία του Αρχαίου Θεάτρου με όμορφες, ήσυχες ακτές.', 'Combines the amazing history of the Ancient Theatre with nice coasts.', '📍 <b>Αξιοθέατα:</b> Αρχαίο Θέατρο, Μικρό Θέατρο.<br>🍽️ <b>Γεύσεις:</b> Ελαιόλαδο, Φρέσκο ψάρι.<br>💡 <b>Tip:</b> Αξίζει να δείτε μια παράσταση το καλοκαίρι.', '📍 <b>Sights:</b> Ancient Theatre.<br>🍽️ <b>Food:</b> Olive oil, Fresh fish.<br>💡 <b>Tip:</b> Watch a play during the summer.', 'https://st3.depositphotos.com/6887034/18171/i/450/depositphotos_181714400-stock-photo-ancient-theater-epidaurus-epidavros-argolida.jpg'),
(43, 'Μυστράς & Σπάρτη', 'Mystras & Sparta', 'Ιστορικός', 'Βουνό', 'Παντός Καιρού', 'All Year', 40, 'Η βυζαντινή καστροπολιτεία του Μυστρά και η ιστορική πόλη της Σπάρτης.', 'The Byzantine castle town of Mystras and historic Sparta.', '📍 <b>Αξιοθέατα:</b> Αρχαιολογικός χώρος Μυστρά, Μουσείο Ελιάς.<br>🍽️ <b>Γεύσεις:</b> Σύγκλινο, Πορτοκάλια.<br>💡 <b>Tip:</b> Φορέστε αθλητικά παπούτσια για την ανάβαση στον Μυστρά.', '📍 <b>Sights:</b> Mystras, Olive Museum.<br>🍽️ <b>Food:</b> Syglino.<br>💡 <b>Tip:</b> Wear sneakers for the climb to Mystras.', 'https://realsparta.gr/portals/0/Images/Mystras/Churches-of-Mystras-1.jpg'),
(44, 'Καστοριά', 'Kastoria', 'Ρομαντικός', 'Πόλη', 'Χειμώνας', 'Winter', 45, 'Μια πανέμορφη αρχοντική πόλη χτισμένη αμφιθεατρικά γύρω από τη λίμνη Ορεστιάδα.', 'A beautiful noble city built around lake Orestiada.', '📍 <b>Αξιοθέατα:</b> Σπήλαιο Δράκου, Παναγία Μαυριώτισσα.<br>🍽️ <b>Γεύσεις:</b> Φασόλια, Κεφτέδες μακρίσιοι.<br>💡 <b>Tip:</b> Ο γύρος της λίμνης το φθινόπωρο είναι μαγικός.', '📍 <b>Sights:</b> Dragon Cave, Mavriotissa.<br>🍽️ <b>Food:</b> Beans, Meatballs.<br>💡 <b>Tip:</b> Walking around the lake in autumn is magical.', 'https://www.travel.gr/wp-content/uploads/2022/03/kASTORIA-GENIKI-2048x1364.jpg'),
(45, 'Αστυπάλαια', 'Astypalaia', 'Ρομαντικός', 'Θάλασσα', 'Καλοκαίρι', 'Summer', 55, 'Η «πεταλούδα του Αιγαίου», με κυκλαδίτικη ομορφιά και δωδεκανησιακό ταμπεραμέντο.', 'The butterfly of the Aegean, with rare beauty.', '📍 <b>Αξιοθέατα:</b> Κάστρο Κουερίνι, Ανεμόμυλοι.<br>🍽️ <b>Γεύσεις:</b> Πουγκιά, Χλωρή (τυρί).<br>💡 <b>Tip:</b> Η θέα από το κάστρο το βράδυ είναι συγκλονιστική.', '📍 <b>Sights:</b> Querini Castle, Windmills.<br>🍽️ <b>Food:</b> Pougia, Chlori cheese.<br>💡 <b>Tip:</b> The view from the castle at night is stunning.', 'https://thumbs.dreamstime.com/b/traditional-greece-beautiful-astypalea-island-view-chora-v-panoramic-houses-sea-93060006.jpg'),
(46, 'Σύμη', 'Symi', 'Ρομαντικός', 'Θάλασσα', 'Καλοκαίρι', 'Summer', 65, 'Ένα πολύχρωμο νεοκλασικό στολίδι στα Δωδεκάνησα, ιδανικό για ζευγάρια.', 'A colorful neoclassical jewel in the Dodecanese.', '📍 <b>Αξιοθέατα:</b> Μονή Πανορμίτη, Γιαλός.<br>🍽️ <b>Γεύσεις:</b> Συμιακό γαριδάκι.<br>💡 <b>Tip:</b> Το λιμάνι της είναι από τα ομορφότερα της Ελλάδας.', '📍 <b>Sights:</b> Panormitis Monastery, Gialos.<br>🍽️ <b>Food:</b> Symi shrimps.<br>💡 <b>Tip:</b> The port is one of the most beautiful in Greece.', 'https://images.ferryhopper.com/destination/Symi.jpg'),
(47, 'Ελάτη & Περτούλι', 'Elati & Pertouli', 'Ρομαντικός', 'Βουνό', 'Χειμώνας', 'Winter', 45, 'Πυκνά ελατοδάση, ξύλινα σαλέ και ένα μικρό χιονοδρομικό κέντρο σε απόσταση αναπνοής.', 'Dense fir forests, chalets, and a ski resort.', '📍 <b>Αξιοθέατα:</b> Χιονοδρομικό, Κόκκινος Βράχος.<br>🍽️ <b>Γεύσεις:</b> Αγριογούρουνο, Χυλοπίτες.<br>💡 <b>Tip:</b> Εξαιρετική επιλογή για ιππασία μέσα στο δάσος.', '📍 <b>Sights:</b> Ski resort, Red Rock.<br>🍽️ <b>Food:</b> Wild boar, Pasta.<br>💡 <b>Tip:</b> Great choice for horseback riding in the forest.', 'https://www.travel.gr/wp-content/uploads/2024/11/Pertouli-2-1-scaled-e1739177778133-2048x1032.jpg'),
(48, 'Τζουμέρκα', 'Tzoumerka', 'Φύση', 'Βουνό', 'Παντός Καιρού', 'All Year', 40, 'Άγρια και παρθένα φύση, καταρράκτες και επιβλητικά βουνά για τους λάτρεις της περιπέτειας.', 'Wild nature, waterfalls, and imposing mountains.', '📍 <b>Αξιοθέατα:</b> Καταρράκτες Κουιάσας, Γεφύρι Πλάκας.<br>🍽️ <b>Γεύσεις:</b> Παραδοσιακές Πίτες, Ντόπιο κρέας.<br>💡 <b>Tip:</b> Ιδανικό μέρος για Rafting στον Άραχθο.', '📍 <b>Sights:</b> Kouiasa Waterfalls, Plaka Bridge.<br>🍽️ <b>Food:</b> Traditional pies, Local meat.<br>💡 <b>Tip:</b> Ideal place for Rafting in Arachthos river.', 'https://www.travel.gr/wp-content/uploads/2024/01/%CE%A0%CF%81%CE%AC%CE%BC%CE%B1%CE%BD%CF%84%CE%B1-2048x1365.jpg'),
(49, 'Φολέγανδρος', 'Folegandros', 'Ρομαντικός', 'Θάλασσα', 'Καλοκαίρι', 'Summer', 70, 'Αυθεντική κυκλαδίτικη ομορφιά με μια από τις πιο εντυπωσιακές Χώρες του Αιγαίου.', 'Authentic Cycladic beauty with a stunning Chora.', '📍 <b>Αξιοθέατα:</b> Παναγία, Κάστρο Χώρας.<br>🍽️ <b>Γεύσεις:</b> Ματσάτα (ζυμαρικά), Καρπουζόπιτα.<br>💡 <b>Tip:</b> Το ηλιοβασίλεμα από την εκκλησία της Παναγίας κόβει την ανάσα.', '📍 <b>Sights:</b> Panagia, Chora Castle.<br>🍽️ <b>Food:</b> Matsata pasta, Watermelon pie.<br>💡 <b>Tip:</b> The sunset from Panagia church is breathtaking.', 'https://www.greeka.com/photos/cyclades/folegandros/hero/folegandros-greece-1920.jpg'),
(50, 'Νάξος', 'Naxos', 'Οικογενειακός', 'Θάλασσα', 'Καλοκαίρι', 'Summer', 55, 'Το μεγαλύτερο νησί των Κυκλάδων, συνδυάζει τέλειες παραλίες με ορεινά παραδοσιακά χωριά.', 'The largest Cycladic island, combining beaches and mountains.', '📍 <b>Αξιοθέατα:</b> Πορτάρα, Απείρανθος.<br>🍽️ <b>Γεύσεις:</b> Γραβιέρα Νάξου, Ντόπιες Πατάτες.<br>💡 <b>Tip:</b> Εξερευνήστε τα ορεινά χωριά, όχι μόνο τις παραλίες.', '📍 <b>Sights:</b> Portara, Apiranthos.<br>🍽️ <b>Food:</b> Naxos Gruyere, Local Potatoes.<br>💡 <b>Tip:</b> Explore the mountain villages, not just the beaches.', 'https://www.visitgreece.gr/images/1743x752/jpg/files/i_1140594041_naxos-portara_1743x752.jpg'),
(51, 'Ξάνθη', 'Xanthi', 'Ρομαντικός', 'Πόλη', 'Παντός Καιρού', 'All Year', 45, 'Η πόλη με τα χίλια χρώματα, την γραφική Παλιά Πόλη και τα πλακόστρωτα.', 'The city of a thousand colors with a picturesque Old Town.', '📍 <b>Αξιοθέατα:</b> Παλιά Πόλη, Ποταμός Κόσυνθος.<br>🍽️ <b>Γεύσεις:</b> Καριόκες, Σουτζούκ Λουκούμ.', '📍 <b>Sights:</b> Old Town, Kosynthos river.<br>🍽️ <b>Food:</b> Kariokes sweets.', 'https://www.travel.gr/wp-content/uploads/2023/11/xanthi-5-2048x1381.jpg'),
(52, 'Δημητσάνα & Βυτίνα', 'Dimitsana & Vytina', 'Ρομαντικός', 'Βουνό', 'Χειμώνας', 'Winter', 60, 'Γραφικά πετρόχτιστα χωριά στην Ορεινή Αρκαδία, ιδανικά για ρομαντικές αποδράσεις.', 'Picturesque stone-built villages in Mountainous Arcadia.', '📍 <b>Αξιοθέατα:</b> Μουσείο Υδροκίνησης, Λούσιος.<br>🍽️ <b>Γεύσεις:</b> Χυλοπίτες, Μέλι ελάτης.', '📍 <b>Sights:</b> Water Power Museum, Lousios river.<br>🍽️ <b>Food:</b> Local pasta, Fir honey.', 'https://www.travel.gr/wp-content/uploads/2024/03/dimitsana-2048x1536.jpg'),
(53, 'Καβάλα', 'Kavala', 'Οικογενειακός', 'Πόλη', 'Παντός Καιρού', 'All Year', 50, 'Πανέμορφη παραθαλάσσια πόλη με πλούσια ιστορία, ιδανική για οικογενειακές βόλτες.', 'Beautiful coastal city with rich history, ideal for families.', '📍 <b>Αξιοθέατα:</b> Παλιά Πόλη, Φρούριο, Ιμαρέτ.<br>🍽️ <b>Γεύσεις:</b> Κουραμπιέδες, Φρέσκο ψάρι.', '📍 <b>Sights:</b> Old Town, Fortress.<br>🍽️ <b>Food:</b> Kourabiedes.', 'https://www.newmoney.gr/wp-content/uploads/2021/11/kavala-1280x853.jpg'),
(54, 'Αλεξανδρούπολη', 'Alexandroupoli', 'Οικογενειακός', 'Πόλη', 'Παντός Καιρού', 'All Year', 45, 'Σύγχρονη πόλη δίπλα στη θάλασσα με τον διάσημο Φάρο και εύκολη πρόσβαση.', 'Modern coastal city with the famous Lighthouse.', '📍 <b>Αξιοθέατα:</b> Φάρος, Δέλτα Έβρου.<br>🍽️ <b>Γεύσεις:</b> Θαλασσινά, Τοπικό κρασί.', '📍 <b>Sights:</b> Lighthouse, Evros Delta.<br>🍽️ <b>Food:</b> Seafood.', 'https://www.travel.gr/wp-content/uploads/2024/10/alexandroupolis-2048x1310.jpg'),
(55, 'Βόλος', 'Volos', 'Διασκέδαση', 'Πόλη', 'Παντός Καιρού', 'All Year', 45, 'Ζωντανή φοιτητούπολη διάσημη για τα τσιπουράδικα της δίπλα στη θάλασσα.', 'Lively student city famous for its tsipouro taverns.', '📍 <b>Αξιοθέατα:</b> Παραλία Βόλου, Μουσείο Πλινθοκεραμοποιίας.<br>🍽️ <b>Γεύσεις:</b> Τσίπουρο με μεζέδες.', '📍 <b>Sights:</b> Volos Beach.<br>🍽️ <b>Food:</b> Tsipouro and meze.', 'https://visitthessaly.gr/sites/default/files/styles/og_image/public/2025-04/D-Volos-N.jpg?itok=uTEx0oo9'),
(56, 'Άγιος Αθανάσιος (Καϊμακτσαλάν)', 'Agios Athanasios', 'Διασκέδαση', 'Βουνό', 'Χειμώνας', 'Winter', 75, 'Το \"Αράχωβα του Βορρά\"! Γραφικό χωριό με έντονη νυχτερινή ζωή και χιονοδρομικό.', 'The Arachova of the North, great nightlife and ski.', '📍 <b>Αξιοθέατα:</b> Χιονοδρομικό Καϊμακτσαλάν.<br>🍽️ <b>Γεύσεις:</b> Κυνήγι, Τσίπουρο.', '📍 <b>Sights:</b> Ski Center.<br>🍽️ <b>Food:</b> Game meat.', 'https://www.kaimaktsalan-voras.com/slider/280/slider_image.jpg'),
(57, 'Ελατοχώρι Πιερίας', 'Elatochori', 'Διασκέδαση', 'Βουνό', 'Χειμώνας', 'Winter', 55, 'Αναπτυσσόμενο χειμερινό θέρετρο με όμορφα σαλέ, ski center και νεανικά στέκια.', 'Developing winter resort with beautiful chalets and a ski center.', '📍 <b>Αξιοθέατα:</b> Χιονοδρομικό Ελατοχωρίου.<br>🍽️ <b>Γεύσεις:</b> Αγριογούρουνο, Κόκκινο κρασί.', '📍 <b>Sights:</b> Elatochori Ski Center.<br>🍽️ <b>Food:</b> Wild boar.', 'https://www.atrionhotel.gr/wp-content/uploads/2022/12/PALIO-ELATOHORI-1-min.jpg'),
(58, 'Έδεσσα', 'Edessa', 'Φύση', 'Πόλη', 'Παντός Καιρού', 'All Year', 40, 'Η πόλη των νερών! Φημισμένη για τους εντυπωσιακούς καταρράκτες της και το πράσινο.', 'The city of waters! Famous for its waterfalls.', '📍 <b>Αξιοθέατα:</b> Καταρράκτες, Πάρκο Κανναβουργείου.<br>🍽️ <b>Γεύσεις:</b> Κεράσια, Πέστροφα.', '📍 <b>Sights:</b> Waterfalls.<br>🍽️ <b>Food:</b> Cherries.', 'https://upload.wikimedia.org/wikipedia/commons/b/b9/%CE%97_%CE%88%CE%B4%CE%B5%CF%83%CF%83%CE%B1_%CE%BA%CE%B1%CE%B9_%CE%BF%CE%B9_%CE%BA%CE%B1%CF%84%CE%B1%CF%81%CF%81%CE%AC%CE%BA%CF%84%CE%B5%CF%82_%CF%84%CE%B7%CF%82..jpg'),
(59, 'Φλώρινα', 'Florina', 'Φύση', 'Πόλη', 'Χειμώνας', 'Winter', 40, 'Κινηματογραφική πόλη, γεμάτη πράσινο, νερά και παλιά αρχοντικά.', 'Cinematic city, full of green, waters and old mansions.', '📍 <b>Αξιοθέατα:</b> Ποταμός Σακουλέβας, Αρχαιολογικό Μουσείο.<br>🍽️ <b>Γεύσεις:</b> Πιπεριές Φλωρίνης, Κεμπάπ.', '📍 <b>Sights:</b> Sakouleva river.<br>🍽️ <b>Food:</b> Florina peppers.', 'https://xronos-kozanis.gr/wp-content/uploads/2025/11/florina-1536x983.jpg'),
(60, 'Κόνιτσα', 'Konitsa', 'Φύση', 'Βουνό', 'Παντός Καιρού', 'All Year', 45, 'Χτισμένη στην πλαγιά του βουνού, ιδανική για δραστηριότητες στα ποτάμια Αώο και Βοϊδομάτη.', 'Built on the mountain slope, ideal for river activities.', '📍 <b>Αξιοθέατα:</b> Γεφύρι Κόνιτσας, Φαράγγι Αώου.<br>🍽️ <b>Γεύσεις:</b> Ηπειρώτικες πίτες.', '📍 <b>Sights:</b> Konitsa Bridge, Aoos Gorge.<br>🍽️ <b>Food:</b> Epirus pies.', 'https://www.naftemporiki.gr/wp-content/uploads/2023/06/konitsa-696x435.jpg'),
(61, 'Μυτιλήνη (Λέσβος)', 'Mytilene (Lesbos)', 'Οικογενειακός', 'Θάλασσα', 'Καλοκαίρι', 'Summer', 45, 'Νησί με τεράστια ιστορία, γραφικά χωριά, μοναδική γαστρονομία και το περίφημο Απολιθωμένο Δάσος.', 'An island with huge history, picturesque villages, unique gastronomy, and the famous Petrified Forest.', '📍 <b>Αξιοθέατα:</b> Κάστρο Μυτιλήνης, Μόλυβος, Απολιθωμένο Δάσος.<br>🍽️ <b>Γεύσεις:</b> Ούζο, Λαδοτύρι, Σαρδέλες Καλλονής.', '📍 <b>Sights:</b> Mytilene Castle, Molyvos, Petrified Forest.<br>🍽️ <b>Food:</b> Ouzo, Ladotyri cheese, Kalloni sardines.', 'https://mitilini.eu/wp-content/uploads/2021/08/%CE%BC%CF%85%CF%84%CE%B9%CE%BB%CE%AE%CE%BD%CE%B7-1.jpg'),
(62, 'Χίος', 'Chios', 'Ιστορικός', 'Θάλασσα', 'Καλοκαίρι', 'Summer', 50, 'Το μυροβόλο νησί της μαστίχας, με τα μοναδικά Μαστιχοχώρια και τα μεσαιωνικά καστροχώρια.', 'The fragrant island of mastic, with the unique Mastichochoria and medieval castle-villages.', '📍 <b>Αξιοθέατα:</b> Πυργί, Μεστά, Νέα Μονή, Μουσείο Μαστίχας.<br>🍽️ <b>Γεύσεις:</b> Μαστίχα, Χιώτικο μανταρίνι.', '📍 <b>Sights:</b> Pyrgi, Mesta, Nea Moni, Mastic Museum.<br>🍽️ <b>Food:</b> Mastic, Chios mandarin.', 'https://outnow.gr/wp-content/uploads/2023/12/xios.jpg'),
(63, 'Σκόπελος', 'Skopelos', 'Ρομαντικός', 'Θάλασσα', 'Καλοκαίρι', 'Summer', 55, 'Καταπράσινο νησί των Σποράδων, διάσημο από την ταινία Mamma Mia, γεμάτο πευκοδάση.', 'A lush green island in the Sporades, famous from the Mamma Mia movie, full of pine forests.', '\n📍 <b>Αξιοθέατα:</b> Άγιος Ιωάννης (Καστρί), Παραλία Καστάνη.<br>🍽️ <b>Γεύσεις:</b> Σκοπελίτικη τυρόπιτα, Ροφός στιφάδο.', '📍 <b>Sights:</b> Agios Ioannis (Kastri), Kastani beach.<br>🍽️ <b>Food:</b> Skopelos cheese pie, Grouper stew.', 'https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcSwxbHYa3i8odAKNY5EYa7WPdjwMPoLd3b1Sg&s');
INSERT INTO `hotels` (`id`, `destination_id`, `category`, `hotel_name`, `image_url`, `location`, `stars`, `price_per_night`, `amenities`, `description`, `latitude`, `longitude`, `phone`, `website`) VALUES
(1, 1, 'Budget', 'Athens Backpackers', 'https://media-cdn.tripadvisor.com/media/photo-s/1c/12/04/37/the-student-travellers.jpg', 'Μακρυγιάννη, Αθήνα', 2, 30, 'Free WiFi, Rooftop Bar', 'Νεανικό hostel μόλις 2 λεπτά από το Μουσείο της Ακρόπολης.', 37.967500, 23.728500, '+30 210 1111111', 'https://example.com/ath1'),
(2, 1, 'Budget', 'City Center Economy', 'https://cf.bstatic.com/xdata/images/hotel/max1024x768/267990731.jpg?k=66a30fad06cca487ffefb72b0024b2539ba86babeb4f7acdd30370f6f03dd984&o=', 'Ομόνοια, Αθήνα', 2, 35, 'Free WiFi, AC', 'Οικονομικά και καθαρά δωμάτια στο κέντρο της πόλης.', 37.983900, 23.728300, '+30 210 1111112', 'https://example.com/ath2'),
(3, 1, 'Budget', 'Plaka Budget Rooms', 'https://q-xx.bstatic.com/xdata/images/hotel/840x460/212084223.jpg?k=7dd9b0bacff5eeb2803aa76c601c607cc4e808f4e1a94bfcdc1a3f61079ca150&o=', 'Πλάκα, Αθήνα', 3, 40, 'AC, Shared Kitchen', 'Φθηνή διαμονή στην πιο γραφική γειτονιά της πρωτεύουσας.', 37.972000, 23.728000, '+30 210 1111113', 'https://example.com/ath3'),
(4, 1, 'Standard', 'Plaka Boutique Hotel', 'https://dynamic-media-cdn.tripadvisor.com/media/photo-o/04/ae/d7/20/single-room.jpg?w=900&h=500&s=1', 'Πλάκα, Αθήνα', 4, 85, 'Πρωινό, Bar, View', 'Μοντέρνα διαμονή με όμορφη θέα και άνετους χώρους.', 37.972500, 23.729000, '+30 210 2222221', 'https://example.com/ath4'),
(5, 1, 'Standard', 'Acropolis View Stay', 'https://cf.bstatic.com/xdata/images/hotel/max1024x768/800277330.jpg?k=c1ca0b921d51224334d79ddbb6d8dedfa149ff6b18c837c68d959e0712dde0ca&o=', 'Κουκάκι, Αθήνα', 4, 95, 'Πρωινό, Γυμναστήριο', 'Άνετο ξενοδοχείο με εξαιρετική πρόσβαση στον ιερό βράχο.', 37.966000, 23.726000, '+30 210 2222222', 'https://example.com/ath5'),
(6, 1, 'Standard', 'Monastiraki Urban Hotel', 'https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcT0TQxL9erkCPs4QS6Eu6QHGBMs2Ou74CRWOQ&s', 'Μοναστηράκι', 4, 105, 'Πρωινό, Rooftop', 'Μοντέρνα αρχιτεκτονική στο πιο ζωντανό σημείο της Αθήνας.', 37.976000, 23.726000, '+30 210 2222223', 'https://example.com/ath6'),
(7, 1, 'Luxury', 'Acropolis Grand Palace', 'https://dynamic-media-cdn.tripadvisor.com/media/photo-o/2c/7a/a2/2a/acropolis-terrace-suites.jpg?w=900&h=500&s=1', 'Σύνταγμα, Αθήνα', 5, 220, 'Rooftop Pool, Spa', 'Πολυτέλεια και ιστορία στην καρδιά της Αθήνας.', 37.975500, 23.734500, '+30 210 3333331', 'https://example.com/ath7'),
